python3 -c "
import json, sys, subprocess
try:
    data = json.load(sys.stdin)
    path = data.get('file_path', '')
    if path.endswith('.py'):
        result = subprocess.run(['python3', '-m', 'py_compile', path], capture_output=True, text=True)
        if result.returncode != 0:
            print(f'[hook] Python syntax error in {path}:')
            print(result.stderr)
            sys.exit(2)
        else:
            print(f'[hook] syntax OK: {path}')
except Exception:
    pass
"

python3 -c "
import json, sys, subprocess, os
try:
    data = json.load(sys.stdin)
    path = data.get('file_path', '')
    if path.endswith('.tf'):
        tf_dir = os.path.dirname(path)
        result = subprocess.run(['terraform', 'fmt', '-check', tf_dir], capture_output=True, text=True)
        if result.returncode != 0:
            print(f'[hook] Terraform fmt needed in {tf_dir} — run: terraform fmt')
        else:
            print(f'[hook] Terraform fmt OK: {path}')
except Exception:
    pass
"
